// IMPORTANTE: el subtotal manda sobre el precio del primer producto.
const h = $json.holded ?? {};
const num = (v) => Number(v) || 0;
const importe = num(h?.subtotal ?? h?.products?.[0]?.price ?? 0);
return [{ json: { importe, nif: $json.nif, email: $json.email, holdedId: $json.holdedId } }];
